import { z } from 'zod';

const envSchema = z.object({
  NODE_ENV: z.enum(['development', 'test', 'production']),
  MONGO_URI: z.string().url(),
  JWT_SECRET: z.string().min(32),
  TELEGRAM_BOT_TOKEN: z.string(),
  PORT: z.preprocess((val) => Number(val), z.number().int()),
});

envSchema.parse(process.env);

export default envSchema;

import { z } from 'zod';

const recurrenceSchema = z.object({
  type: z.enum(['daily', 'weekly', 'custom']),
  daysOfWeek: z.array(z.number().min(0).max(6)).optional(),
  time: z.string().regex(/^\d{2}:\d{2}$/), // 24h format e.g. 23:59
});

export const createTaskSchema = z.object({
  groupId: z.string(),
  title: z.string().min(1),
  description: z.string().optional(),
  assignees: z.array(z.string()),
  recurrence: recurrenceSchema,
});

import { Task } from 'models/task.model';

export interface TaskDTO {
  id: string;
  title: string;
  description: string;
  assignees: string[];
  rotationIndex: number;
  recurrence: {
    type: 'daily' | 'weekly' | 'custom';
    daysOfWeek?: number[];
    time: string;
  };
  status: 'active' | 'paused';
}

export const taskToDTO = (task: Task): TaskDTO => ({
  id: task._id.toHexString(),
  title: task.title,
  description: task.description,
  assignees: task.assignees.map(id => id.toHexString()),
  rotationIndex: task.rotationIndex,
  recurrence: task.recurrence,
  status: task.status,
});

import { TaskModel } from '../models/task.model';
import { TaskDTO } from '../dtos/task.dto';

export class TaskRepository {
  async createTask(taskDTO: TaskDTO): Promise<TaskDTO> {
    const task = new TaskModel(taskDTO);
    await task.save();
    return taskToDTO(task);
  }

  async findTaskById(id: string): Promise<TaskDTO | null> {
    const task = await TaskModel.findById(id);
    return task ? taskToDTO(task) : null;
  }

  // ... additional methods
}

import cron from 'node-cron';
import { TaskRepository } from '../repositories/task.repository';
import { sendNotification } from '../services/notification.service';
import { logger } from '../utils/logger';

class SchedulingEngine {
  private taskRepo = new TaskRepository();

  public initialize() {
    cron.schedule('* * * * *', () => {
      logger.info('Running scheduled tasks check at ' + new Date().toISOString());
      this.checkTasks();
    });
  }

  private async checkTasks(): Promise<void> {
    const tasks = await this.taskRepo.findAllActiveTasks();
    for (const task of tasks) {
      try {
        await sendNotification(task);
        logger.info(`Notification sent for task ${task.id}`);
      } catch (error) {
        logger.error(`Failed to send notification for task ${task.id}: ${error.message}`);
        // Implement retry logic here
      }
    }
  }
}

export default new SchedulingEngine();

import { createLogger, format, transports } from 'winston';

export const logger = createLogger({
  level: 'info',
  format: format.combine(
    format.timestamp(),
    format.printf(({ timestamp, level, message }) => {
      return `${timestamp} [${level}]: ${message}`;
    })
  ),
  transports: [
    new transports.Console(),
    // new transports.File({ filename: 'combined.log' })
  ],
});
